#include<bits/stdc++.h>
using namespace std;
vector<pair<int,int>> mp[1010];
int n,m,k;
int h[1010],f[1010][1010][2],g[1010][2];
void dfs(int x,int fa=-1)
{
    f[x][0][0]=f[x][1][1]=0;
    for(auto i:mp[x])
    {
        int v=i.first,val=i.second;
        if(v!=fa)
        {
            dfs(v,x);
            memcpy(g,f[x],sizeof(f[x]));
            memset(f[x],0x3f,sizeof(f[x]));
            for(int i=0;i<=k;i++)
            {
                for(int j=0;j<=i;j++)
                {
                    f[x][i][0]=min({f[x][i][0],f[v][j][0]+g[i-j][0]+(m==2)*val,f[v][j][1]+g[i-j][0]});
                    f[x][i][1]=min({f[x][i][1],f[v][j][1]+g[i-j][1]+val,f[v][j][0]+g[i-j][1]});
                }
            }
        }
    }
}
int main()
{
    memset(f,0x3f,sizeof(f));
    scanf("%d%d%d",&n,&m,&k);
    if(n-k<m-1)
    {
        printf("-1");
        return 0;
    }
    for(int i=1;i<n;i++)
    {
        int u,v,w;
        scanf("%d%d%d",&u,&v,&w);
        mp[u].push_back(make_pair(v,w));
        mp[v].push_back(make_pair(u,w));
    }
    dfs(1);
    printf("%d",f[1][k][1]);
    return 0;
}
